                CUBLAS_OP_N, CUBLAS_OP_N,
                d, d, 16,
                &alpha,
                U.data_ptr<float>(), d,
                A.data_ptr<float>(), 16,
                &beta1,
                Y.data_ptr<float>(), d);

    return Y;
}

